"use client";

import { type DialogProps, Dialog as DialogRoot } from "./dialog";
import { DialogAction, type DialogActionProps } from "./dialog-action";
import { DialogBody, type DialogBodyProps } from "./dialog-body";
import { DialogClose, type DialogCloseProps } from "./dialog-close";
import { DialogCloseIcon, type DialogCloseIconProps } from "./dialog-close-icon";
import { DialogContent, type DialogContentProps, type DialogCorners, dialogContentVariants } from "./dialog-content";
import { DialogDescription, type DialogDescriptionProps } from "./dialog-description";
import { DialogFooter, type DialogFooterProps } from "./dialog-footer";
import { DialogHeader, type DialogHeaderProps } from "./dialog-header";
import { DialogKeyboardHints, type DialogKeyboardHintsProps, type KeyboardHint } from "./dialog-keyboard-hints";
import { DialogTitle, type DialogTitleProps } from "./dialog-title";
import { DialogTrigger, type DialogTriggerProps, type DialogTriggerRenderProps } from "./dialog-trigger";

const Dialog = Object.assign(DialogRoot, {
  Trigger: DialogTrigger,
  Content: DialogContent,
  Header: DialogHeader,
  Title: DialogTitle,
  Description: DialogDescription,
  Body: DialogBody,
  Footer: DialogFooter,
  KeyboardHints: DialogKeyboardHints,
  Close: DialogClose,
  CloseIcon: DialogCloseIcon,
  Action: DialogAction,
});

export { Dialog, type DialogProps };
export { DialogTrigger, type DialogTriggerProps, type DialogTriggerRenderProps };
export { DialogContent, dialogContentVariants, type DialogContentProps, type DialogCorners };
export { DialogHeader, type DialogHeaderProps };
export { DialogTitle, type DialogTitleProps };
export { DialogDescription, type DialogDescriptionProps };
export { DialogBody, type DialogBodyProps };
export { DialogFooter, type DialogFooterProps };
export { DialogClose, type DialogCloseProps };
export { DialogCloseIcon, type DialogCloseIconProps };
export { DialogAction, type DialogActionProps };
export { DialogKeyboardHints, type DialogKeyboardHintsProps, type KeyboardHint };

"use client";

import { type ReactNode, useId, useMemo, useRef } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { DialogContext } from "./dialog-context";

export interface DialogProps {
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  children: ReactNode;
}

function DialogRoot({ open: controlledOpen, defaultOpen, onOpenChange, children }: DialogProps) {
  const [isOpen, setIsOpen] = useControllableState({
    value: controlledOpen,
    defaultValue: defaultOpen ?? false,
    onChange: onOpenChange,
  });
  const dialogId = useId();
  const triggerRef = useRef<HTMLElement>(null);

  const contextValue = useMemo(
    () => ({
      open: isOpen,
      onOpenChange: setIsOpen,
      contentId: `${dialogId}-content`,
      titleId: `${dialogId}-title`,
      descriptionId: `${dialogId}-description`,
      triggerRef,
    }),
    [isOpen, setIsOpen, dialogId],
  );

  return (
    <DialogContext value={contextValue}>
      {children}
    </DialogContext>
  );
}

export { DialogRoot as Dialog };

"use client";

import { createContext, type MouseEventHandler, type RefObject, useContext } from "react";

export interface DialogContextValue {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  contentId: string;
  titleId: string;
  descriptionId: string;
  triggerRef: RefObject<HTMLElement | null>;
}

export const DialogContext = createContext<DialogContextValue | undefined>(undefined);

export function useDialogContext() {
  const context = useContext(DialogContext);
  if (!context) {
    throw new Error("Dialog compound components must be used within a Dialog");
  }
  return context;
}

export function useDialogDismiss<T extends HTMLElement = HTMLElement>(onClick?: MouseEventHandler<T>): MouseEventHandler<T> {
  const { onOpenChange } = useDialogContext();
  return (e) => {
    onClick?.(e);
    if (!e.defaultPrevented) onOpenChange(false);
  };
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import {
  Children,
  type HTMLAttributes,
  isValidElement,
  type ReactNode,
  type RefObject,
  type SyntheticEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
} from "react";
import { useFocusRestore } from "@/hooks/use-focus-restore";
import { mergeIds } from "@/lib/aria";
import { cn } from "@/lib/utils";
import { DialogShell } from "../shared/dialog-shell";
import { PortalContainerProvider } from "../shared/portal-context";
import { useDialogContext } from "./dialog-context";
import { DialogDescription } from "./dialog-description";
import { DialogTitle } from "./dialog-title";

export type DialogCorners = "none" | "subtle" | "standard" | "bold" | "outset";

export const dialogContentVariants = cva(
  "relative w-full max-h-[90vh] flex flex-col bg-background text-foreground shadow-2xl m-auto",
  {
    variants: {
      size: {
        sm: "max-w-sm",
        md: "max-w-2xl",
        lg: "max-w-4xl",
        full: "max-w-full",
      },
      frame: {
        border: "border border-border",
        none: "",
      },
    },
    defaultVariants: {
      size: "md",
      frame: "border",
    },
  }
);

const FALLBACK_DIALOG_LABEL = "Dialog";

export interface DialogContentProps
  extends VariantProps<typeof dialogContentVariants>,
    Omit<HTMLAttributes<HTMLDialogElement>, "children" | "className"> {
  children: ReactNode;
  className?: string;
  corners?: DialogCorners | null;
  role?: "dialog" | "alertdialog";
  closeOnBackdropClick?: boolean;
  initialFocus?: RefObject<HTMLElement | null>;
  onCancel?: (e: SyntheticEvent<HTMLDialogElement>) => void;
  onEscapeKeyDown?: (e: SyntheticEvent<HTMLDialogElement>) => void;
}

function hasNonEmptyText(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

type AccessibleNameInput = {
  ariaLabel: string | undefined;
  ariaLabelledBy: string | undefined;
  titleId: string;
  hasRenderableTitle: boolean;
};

type AccessibleNameOutput = {
  "aria-label": string | undefined;
  "aria-labelledby": string | undefined;
};

function resolveAccessibleName({
  ariaLabel,
  ariaLabelledBy,
  titleId,
  hasRenderableTitle,
}: AccessibleNameInput): AccessibleNameOutput {
  if (hasNonEmptyText(ariaLabelledBy)) {
    return { "aria-label": undefined, "aria-labelledby": ariaLabelledBy };
  }
  if (hasNonEmptyText(ariaLabel)) {
    return { "aria-label": ariaLabel, "aria-labelledby": undefined };
  }
  if (hasRenderableTitle) {
    return { "aria-label": undefined, "aria-labelledby": titleId };
  }
  return { "aria-label": FALLBACK_DIALOG_LABEL, "aria-labelledby": undefined };
}

/**
 * Provide an accessible name through one of three paths (precedence order):
 *
 * 1. `aria-labelledby` pointing at existing element id(s);
 * 2. an explicit `aria-label` string;
 * 3. a rendered `<Dialog.Title>`, whose id is wired automatically.
 *
 * ```tsx
 * <Dialog.Content><Dialog.Title>Settings</Dialog.Title>…</Dialog.Content>
 * <Dialog.Content aria-label="Settings">…</Dialog.Content>
 * <Dialog.Content aria-labelledby="settings-heading">…</Dialog.Content>
 * ```
 *
 * If none are present the dialog falls back to the label "Dialog" and warns in
 * dev so the dialog still has a usable name rather than failing to open.
 */
export function DialogContent({
  children,
  className,
  size,
  frame,
  corners,
  closeOnBackdropClick = true,
  initialFocus,
  onEscapeKeyDown,
  onCancel,
  onAnimationEnd,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  "aria-describedby": ariaDescribedBy,
  ...rest
}: DialogContentProps) {
  const { open, onOpenChange, contentId, titleId, descriptionId, triggerRef } = useDialogContext();
  const close = () => onOpenChange(false);
  const shellRef = useRef<HTMLDialogElement>(null);
  const [container, setContainer] = useState<Element | null>(null);
  const focusRestore = useFocusRestore({
    fallback: triggerRef.current,
    restoreOnUnmount: false,
  });
  const hasRenderableTitle = containsDialogTitleElement(children);
  const hasRenderableDescription = containsDialogDescriptionElement(children);
  const resolvedFrame = frame ?? "border";
  const resolvedCorners = corners ?? "none";
  const accessibleName = resolveAccessibleName({
    ariaLabel,
    ariaLabelledBy,
    titleId,
    hasRenderableTitle,
  });

  const isFallbackName = accessibleName["aria-label"] === FALLBACK_DIALOG_LABEL;

  useEffect(() => {
    if (process.env.NODE_ENV !== "production" && isFallbackName) {
      console.warn(
        "Dialog: No accessible name provided. Add a <Dialog.Title>, aria-label, or aria-labelledby prop.",
      );
    }
  }, [isFallbackName]);

  const resolvedDescribedBy = mergeIds(
    ariaDescribedBy,
    hasRenderableDescription ? descriptionId : undefined,
  );

  const setShellRef = useCallback((node: HTMLDialogElement | null) => {
    shellRef.current = node;
    setContainer(node);
  }, []);

  return (
    <DialogShell
      {...rest}
      open={open}
      id={contentId}
      dialogRef={setShellRef}
      initialFocus={initialFocus}
      onBackdropClick={closeOnBackdropClick ? close : undefined}
      onCancel={(e) => {
        onCancel?.(e);
        if (e.defaultPrevented) return;
        onEscapeKeyDown?.(e);
        if (!e.defaultPrevented) close();
      }}
      onBeforeShowModal={focusRestore.capture}
      onClose={focusRestore.restore}
      onAnimationEnd={onAnimationEnd}
      className={cn(dialogContentVariants({ size, frame }), className)}
      data-slot="dialog-content"
      data-frame={resolvedFrame}
      data-corners={resolvedCorners}
      aria-modal="true"
      aria-label={accessibleName["aria-label"]}
      aria-labelledby={accessibleName["aria-labelledby"]}
      aria-describedby={resolvedDescribedBy}
    >
      <PortalContainerProvider container={container}>
        {resolvedCorners !== "none" ? (
          <span aria-hidden="true" className="dlg-corners" />
        ) : null}
        {children}
      </PortalContainerProvider>
    </DialogShell>
  );
}

function containsDialogTitleElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === DialogTitle) return true;
    return containsDialogTitleElement(child.props.children);
  });
}

function containsDialogDescriptionElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === DialogDescription) return true;
    return containsDialogDescriptionElement(child.props.children);
  });
}

"use client";

import type { HTMLAttributes } from "react";
import { cn } from "@/lib/utils";

export interface DialogHeaderProps extends HTMLAttributes<HTMLDivElement> {
  marker?: "bar" | "none";
}

export function DialogHeader({
  className,
  children,
  marker = "bar",
  ...props
}: DialogHeaderProps) {
  if (marker === "bar") {
    return (
      <div
        data-slot="dialog-header"
        className={cn("flex gap-3 px-5 pt-4 pb-3 shrink-0", className)}
        {...props}
      >
        <span aria-hidden="true" className="w-1 self-stretch bg-foreground" />
        <div className="flex flex-col gap-1 min-w-0 flex-1">{children}</div>
      </div>
    );
  }

  return (
    <div
      data-slot="dialog-header"
      className={cn("flex flex-col gap-1 min-w-0 px-5 pt-4 pb-3 shrink-0", className)}
      {...props}
    >
      {children}
    </div>
  );
}

"use client";

import type { HTMLAttributes } from "react";
import { cn } from "@/lib/utils";
import { useDialogContext } from "./dialog-context";

export interface DialogTitleProps extends HTMLAttributes<HTMLHeadingElement> {
  as?: "h1" | "h2" | "h3" | "h4" | "h5" | "h6";
  meta?: string;
}

export function DialogTitle({
  children,
  className,
  as: Tag = "h2",
  meta,
  ...props
}: DialogTitleProps) {
  const { titleId } = useDialogContext();

  return (
    <Tag
      {...props}
      id={titleId}
      data-slot="dialog-title"
      className={cn(
        "flex items-center gap-2.5 text-sm font-bold text-foreground",
        className,
      )}
    >
      <span className="min-w-0 flex-1 truncate">{children}</span>
      {meta ? (
        <span
          aria-hidden="true"
          className="ml-auto shrink-0 text-[length:var(--dlg-title-meta-size)] font-normal uppercase tracking-[var(--dlg-title-meta-tracking)] text-muted"
        >
          {meta}
        </span>
      ) : null}
    </Tag>
  );
}

